import requests, re, urllib.parse, hashlib
base='http://127.0.0.1:9101'
s=requests.Session()
paths=['/','/robots.txt','/sitemap.xml']
seen=set()
for p in paths:
    url=urllib.parse.urljoin(base,p)
    try:
        r=s.get(url,timeout=5,allow_redirects=False)
        print('\n=== GET',p,'===')
        print('STATUS',r.status_code)
        print('HEADERS')
        for k,v in r.headers.items(): print(f'{k}: {v}')
        print('LEN',len(r.content),'SHA',hashlib.sha256(r.content).hexdigest())
        print(r.text)
        # extract links/assets/forms
        for m in re.findall(r'''(?:href|src|action)=["']([^"']+)["']''', r.text, re.I):
            print('FOUND_ATTR',m)
            seen.add(urllib.parse.urljoin(base,m))
    except Exception as e: print('ERR',p,e)
print('\nASSETS/ROUTES',*sorted(seen),sep='\n')
# fetch js/css/html linked assets same-origin
for u in sorted(seen):
    if u.startswith(base):
        try:
            r=s.get(u,timeout=5,allow_redirects=False)
            print('\n=== FETCH',u,'===')
            print('STATUS',r.status_code,'CT',r.headers.get('content-type'),'LEN',len(r.content),'SHA',hashlib.sha256(r.content).hexdigest())
            txt=r.text
            print(txt)
            for pat in [r'fetch\(([^\)]*)\)', r'XMLHttpRequest', r'axios\.[a-z]+\(([^\)]*)\)', r'\$\.ajax\((.*?)\)', r'["\']([^"\']*(?:php|/api|\?id=|admin|login|search|profile)[^"\']*)["\']']:
                for m in re.findall(pat, txt, re.I|re.S): print('FOUND_JS',m)
        except Exception as e: print('ERR asset',u,e)
